class Solution(object):
    def summaryRanges(self, nums):
        """
        :type nums: List[int]
        :rtype: List[str]
        """
        res = []
        if not nums:
            return res

        start = nums[0]
        for i in range(1, len(nums)):
            if nums[i] - nums[i-1] == 1:
                continue
            elif nums[i-1] == start:
                res.append(str(start))
            else:
                res.append(str(start) + '->' + str(nums[i-1]))
            start = nums[i]

        if start == nums[-1]:
            res.append(str(start))
        else:
            res.append(str(start) + '->' + str(nums[-1]))

        return res

distinct-subsequences.solution:
class Solution(object):
    def numDistinct(self, s, t):
        """
        :type s: str
        :type t: str
        :rtype: int
        """

        m, n = len(s), len(t)

        if n > m:
            return 0

        dp = [[0] * (n+1) for _ in range(m+1)]

        for i in range(m+1):
            dp[i][0] = 1

        for i in range(1, m+1):
            for j in range(1, n+1):
                if s[i-1] == t[j-1]:
                    dp[i][j] = dp[i-1][j-1] + dp[i-1][j]
                else:
                    dp[i][j] = dp[i-1][j]

        return dp[m][n]

