class Solution(object):
    def getPermutation(self, n, k):
        import math
        f = [1]
        for i in range(1, n):
            f.append(f[-1]*i)

        k -= 1
        nums = list(range(1, n+1))
        permutation = []

        for i in range(n, 0, -1):
            idx = k // f[i - 1]
            k %= f[i - 1]
            permutation.append(str(nums.pop(idx)))

        return "".join(permutation)

