def addOperators(self, num, target):
    def dfs(idx, path, value, prev):
        if idx == len(num) and value == target:
            result.append(path)

        for i in range(idx + 1, len(num) + 1):
            if i > idx + 1 and num[idx] == "0":
                break

            s = num[idx:i]
            curr = int(s)

            if idx == 0:
                dfs(i, s, curr, curr)
            else:
                dfs(i, path + "+" + s, value + curr, curr)
                dfs(i, path + "-" + s, value - curr, -curr)
                dfs(i, path + "*" + s, value - prev + prev * curr, prev * curr)

    result = []
    dfs(0, "", 0, 0)

    return result

