class Solution:
    def canCompleteCircuit(self, gas: List[int], cost: List[int]) -> int:
        total_surplus = 0
        curr_surplus = 0
        start = 0
        for i in range(len(gas)):
            total_surplus += gas[i] - cost[i]
            curr_surplus += gas[i] - cost[i]
            if curr_surplus < 0:
                curr_surplus = 0
                start = i + 1
        return -1 if total_surplus < 0 else start

