def checkPerfectNumber(num):
    if num <= 1:
        return False

    divisors_sum = 1
    for i in range(2, int(num**0.5) + 1):
        if num % i == 0:
            divisors_sum += i
            if i != num // i:
                divisors_sum += num // i

    return divisors_sum == num

