class Solution(object):
    def calculateMinimumHP(self, dungeon):
        """
        :type dungeon: List[List[int]]
        :rtype: int
        """
        m, n = len(dungeon), len(dungeon[0])
        memo = {}

        def dfs(i, j):
            if (i, j) in memo:
                return memo[(i, j)]

            if i == m-1 and j == n-1:
                return max(1, 1-dungeon[i][j])

            if i == m-1:
                res = dfs(i, j+1) - dungeon[i][j]
            elif j == n-1:
                res = dfs(i+1, j) - dungeon[i][j]
            else:
                res = min(dfs(i+1, j), dfs(i, j+1)) - dungeon[i][j]
            memo[(i, j)] = max(1, res)
            return memo[(i, j)]

        return dfs(0, 0)

