class Solution:
    def smallestDistancePair(self, nums, k):
        nums.sort()
        low, high = 0, nums[-1] - nums[0]

        def possible(guess):
            count = left = 0
            for right, x in enumerate(nums):
                while x-nums[left] > guess:
                    left += 1
                count += right - left
            return count >= k

        while low < high:
            mid = (low + high) // 2
            if possible(mid):
                high = mid
            else:
                low = mid + 1

        return low

