class Solution(object):
    def reverseVowels(self, s):
        """
        :type s: str
        :rtype: str
        """

        def isVowel(ch):
            return ch in 'aeiouAEIOU'

        s = list(s)
        start, end = 0, len(s) - 1
        while start < end:
            while start < end and not isVowel(s[start]):
                start += 1
            while start < end and not isVowel(s[end]):
                end -= 1
            s[start], s[end] = s[end], s[start]
            start, end = start + 1, end - 1
        return ''.join(s)

