class Solution(object):
    def searchRange(self, nums, target):
        def findBound(nums, target, isFirstOccurrence):
            ans = -1
            start, end = 0, len(nums) - 1
            while start <= end:
                mid = (start + end) // 2
                if nums[mid] == target:
                    if isFirstOccurrence:
                        ans = mid
                        end = mid - 1
                    else:
                        ans = mid
                        start = mid + 1
                elif nums[mid] < target:
                    start = mid + 1
                else:
                    end = mid - 1
            return ans

        first = findBound(nums, target, True)
        last = findBound(nums, target, False)

        return [first, last]

