best-time-to-buy-and-sell-stock-iv.solution:
class Solution(object):
    def maxProfit(self, k, prices):
        n = len(prices)
        if k > n//2: # if k is large, which means no limit, apply the unlimited-k case
            return self.quickSolve(prices)

        dp = [[0]*n for _ in range(k+1)] # dp[i][j] represents max profit at most i transactions till day j
        for i in range(1, k+1): 
            max_diff = -prices[0] # the highest profit of just doing the transaction before i-1, when last transaction is day 0
            for j in range(1, n): 
                dp[i][j] = max(dp[i][j-1], prices[j] + max_diff) # dp[i][j-1] if we don't do the transaction on day j, or prices[j] + max_diff if we do the transaction on day j
                max_diff = max(max_diff, dp[i-1][j-1] - prices[j]) # max_diff is either the max_diff we had at the last step (dp[i-1][j-1] - prices[j]) or doing a transaction before i-1 on day j

        return dp[k][n-1]

    def quickSolve(self, prices):
        res = 0
        for i in range(1, len(prices)):
            if prices[i] > prices[i-1]:
                res += prices[i] - prices[i-1]
        return res

