class Solution(object):
    def firstUniqChar(self, s):
        """
        :type s: str
        :rtype: int
        """
        frequency = {}

        # build a hash map with the frequency of each character
        for char in s:
            if char in frequency:
                frequency[char] += 1
            else:
                frequency[char] = 1

        # find the index of the first non-repeating character
        for i in range(len(s)):
            if frequency[s[i]] == 1:
                return i

        # return -1 if there is no non-repeating character
        return -1

contains-duplicate-iii.solution:
class Solution(object):
    def containsNearbyAlmostDuplicate(self, nums, indexDiff, valueDiff):
        """
        :type nums: List[int]
        :type indexDiff: int
        :type valueDiff: int
        :rtype: bool
        """
        # Input validation
        if not nums or indexDiff <= 0 or valueDiff < 0:
            return False

        n = len(nums)
        buckets = {}
        bucket_size = valueDiff + 1

        for i in range(n):
            # Calculate the bucket where the current number belongs
            bucket_num = nums[i] // bucket_size

            # Check the neighboring buckets for the existence of a number that satisfies the conditions
            if bucket_num in buckets:
                return True
            if bucket_num - 1 in buckets and abs(nums[i] - buckets[bucket_num - 1]) < bucket_size:
                return True
            if bucket_num + 1 in buckets and abs(nums[i] - buckets[bucket_num + 1]) < bucket_size:
                return True

            # Insert the current number into the corresponding bucket
            buckets[bucket_num] = nums[i]

            # Remove the number that's no longer in the required distance
            if i >= indexDiff:
                del buckets[nums[i - indexDiff] // bucket_size]

        return False

