class Solution(object):
    def addStrings(self, num1, num2):
        """
        :type num1: str
        :type num2: str
        :rtype: str
        """
        carry = 0
        res = []

        # Make sure num1 is always larger
        if len(num1) < len(num2):
            num1, num2 = num2, num1
        num1, num2 = num1[::-1], num2[::-1]

        for i in range(0, len(num1)):
            n1 = int(num1[i])
            if i < len(num2):
                n2 = int(num2[i])
            else:
                n2 = 0

            tmp = n1 + n2 + carry
            carry = tmp // 10
            res.append(str(tmp % 10))

        if carry:
            res.append(str(carry))

        return ''.join(res[::-1])

basic-calculator.solution:
class Solution(object):
    def calculate(self, s):
        stack_operand = []
        stack_operator = []

        # adding a dummy '(' at the beginning and ')' at the end of the string
        s = "(" + s + ")"

        # iterate through the string
        for char in s:
            # Skip space characters
            if char.isspace():
                continue

            # if char is digit, push it to the stack of operand
            elif char.isdigit():
                operand = int(char)
                # if the last operator in the stack is '*', we perform the multiplication, otherwise, we push it to the operand stack
                if stack_operator and stack_operator[-1] == '*':
                    operand = stack_operand.pop() * operand
                    stack_operator.pop()
                else:
                    stack_operand.append(operand)

            # when we encounter a '(' or ')'
            elif char in ['(', ')']:
                # if it's a '(' push it to the stack of operator
                if char == '(':
                    stack_operator.append(char)
                # if it's a ')', we need to evaluate the expression inside the parentheses
                else:
                    # while top of the operator stack is not '('
                    while stack_operator[-1] != '(':
                        op = stack_operator.pop()
                        right_operand = stack_operand.pop()
                        left_operand = stack_operand.pop()
                        # Perform operation based on operator
                        if op == '+':
                            stack_operand.append(left_operand + right_operand)
                        else:
                            stack_operand.append(left_operand - right_operand)
                    # pop out '('
                    stack_operator.pop()

            # when we encounter an operator (+/-)
            else:
                while stack_operator and stack_operator[-1] in ['+', '-', '*', '/']:
                    op = stack_operator.pop()
                    right_operand = stack_operand.pop()
                    left_operand = stack_operand.pop()
                    # Perform operation based on operator
                    if op == '+':
                        stack_operand.append(left_operand + right_operand)
                    else:
                        stack_operand.append(left_operand - right_operand)
                stack_operator.append(char)

        return stack_operand[0]

