import heapq

class Solution(object):
    def findMaximizedCapital(self, k, w, profits, capital):
        projects = sorted([(capital[i], profits[i]) for i in range(len(profits))], key=lambda x: (x[0], x[1]))
        available_projects = []
        index = 0
        for _ in range(k):
            while index < len(projects) and projects[index][0] <= w:
                heapq.heappush(available_projects, -projects[index][1])
                index += 1
            if available_projects:
                w -= heapq.heappop(available_projects)
            else:
                break
        return w

