maximum-gap.solution:
class Solution:
    def maximumGap(self, nums: List[int]) -> int:
        if len(nums) < 2:
            return 0
        else:
            max_num = max(nums)
            min_num = min(nums)
            size = (max_num - min_num) // (len(nums)-1)
            min_arr = [float('inf')] * (len(nums)-1)
            max_arr = [float('-inf')] * (len(nums)-1)
            for num in nums:
                idx = (num-min_num)//size if size else 0
                min_arr[idx] = min(min_arr[idx],num)
                max_arr[idx] = max(max_arr[idx],num)
            previous = min_num
            ans = 0
            for i in range(len(nums)-1):
                if min_arr[i] == float('inf') and max_arr[i] == float('-inf'):
                    continue
                ans = max(ans, min_arr[i]-previous)
                previous = max_arr[i]
            ans = max(ans, max_num-previous)
            return ans

