def countRangeSum(self, nums, lower, upper):
    def countRangeSumRecursive(sum_array, start, mid, end, lower, upper):
        count = 0
        right_sum_start = mid + 1
        right_sum_end = mid + 1
        for left_sum in sum_array[start:mid+1]:
            while right_sum_end <= end and sum_array[right_sum_end] - left_sum < lower:
                right_sum_end += 1
            while right_sum_start <= end and sum_array[right_sum_start] - left_sum <= upper:
                right_sum_start += 1
            count += right_sum_start - right_sum_end
        sum_array[start:end+1] = sorted(sum_array[start:end+1])
        return count

    def countRangeSumRecursiveHelper(sum_array, start, end, lower, upper):
        if start == end:
            return 0
        mid = (start + end) // 2
        count = countRangeSumRecursiveHelper(sum_array, start, mid, lower, upper) + countRangeSumRecursiveHelper(sum_array, mid+1, end, lower, upper)
        count += countRangeSumRecursive(sum_array, start, mid, mid+1, end, lower, upper)
        return count
    sum_array = [0] * (len(nums) + 1)
    for i in range(1, len(sum_array)):
        sum_array[i] = sum_array[i-1] + nums[i-1]
    return countRangeSumRecursiveHelper(sum_array, 0, len(sum_array)-1, lower, upper)

