class Solution(object):
    def numDecodings(self, s):
        if not s:
            return 0

        dp = [0] * (len(s) + 1)
        dp[0] = 1 # one way to decode an empty string
        dp[1] = 0 if s[0] == '0' else 1 # one way to decode a single digit string if it's not '0'

        for i in range(2, len(s) + 1):
            if s[i-1] != '0':
                dp[i] += dp[i - 1]

            two_digit = int(s[i-2:i])
            if 10 <= two_digit <= 26:
                dp[i] += dp[i - 2]

