class Solution(object):
    def wordBreak(self, s, wordDict):
        """
        :type s: str
        :type wordDict: List[str]
        :rtype: bool
        """
        return self._word_break(s, wordDict, {})

    def _word_break(self, s, wordDict, memo):
        if s in self.memo: 
            return self.memo[s]
        if not s: 
            return True
        for word in wordDict:
            if s.startswith(word):
                suffix = s[len(word):]
                if self._word_break(suffix, wordDict, memo):
                    self.memo[s] = True
                    return True
        self.memo[s] = False
        return False

