import heapq

class Solution(object):
    def smallestRange(self, nums):
        heap, max_val, res = [], float('-inf'), [float('-inf'), float('inf')]

        for i in range(len(nums)):
            heapq.heappush(heap, (nums[i][0], i, 0))
            max_val = max(max_val, nums[i][0])

        while True:
            min_val, row, index = heapq.heappop(heap)

            if max_val - min_val < res[1] - res[0]:
                res = [min_val, max_val]

            if index + 1 == len(nums[row]):
                break

            max_val = max(max_val, nums[row][index + 1])
            heapq.heappush(heap, (nums[row][index + 1], row, index + 1))

        return res

