class Solution(object):
    def removeInvalidParentheses(self, s):
        """
        :type s: str
        :rtype: List[str]
        """
        def is_valid(s):
            count = 0
            for c in s:
                if c == '(':
                    count += 1
                if c == ')':
                    count -= 1
                    if count < 0:
                        return False
            return count == 0

        visited = set([s])
        queue = collections.deque([s])
        result = []
        found = False

        while queue:
            cur = queue.popleft()
            if is_valid(cur):
                result.append(cur)
                found = True

            if found:
                continue

            for i in range(len(cur)):
                if cur[i] in ('(', ')'):
                    next_str = cur[:i] + cur[i+1:]
                    if next_str not in visited:
                        visited.add(next_str)
                        queue.append(next_str)

        return result

