class Solution(object):
    def minCut(self, s):
        n = len(s)
        lookup = [[False]*n for _ in range(n)]

        # Initialize lookup table
        for i in range(n):
            lookup[i][i] = True

        # Check for substring equality
        for i in range(n-1):
            lookup[i][i+1] = s[i] == s[i+1]

        # Check for palindrome of length greater than 2  
        for length in range(3, n+1):
            for i in range(n-length+1):
                j = i+length-1
                lookup[i][j] = (s[i] == s[j]) and lookup[i+1][j-1]

        # Partition the string into palindromes
        cut = [n]*n
        for i in range(n):
            if lookup[0][i]:
                cut[i] = 0
            else:
                for j in range(i):
                    if lookup[j+1][i] and 1 + cut[j] < cut[i]:
                        cut[i] = 1 + cut[j]

        return cut[-1]

