def preimageSizeFZF(self, k):
    def count_fact(num, power):
        count = 0
        pow2 = power
        while power > 0:
            count += num//power
            power //= 5
        return count * pow2

    left, right = 0, 10**9+1
    while right - left > 1:
        mid = (left + right) // 2
        if count_fact(mid, 5**k) > count_fact(mid-1, 5**k):
            left = mid
        else:
            right = mid

    start = right
    if count_fact(right, 5**k) == count_fact(right-1, 5**k):
        start -= 1
    return 5**k - count_fact(start, 5**k) + count_fact(start+1, 5**k)

