class Solution:
    def containVirus(self, isInfected: List[List[int]]) -> int:
        self.grid = isInfected
        self.m, self.n = len(isInfected), len(isInfected[0])
        self.region = {}    # <Region#, Area>
        self.infectedNeighbors = {}  # <Region#, [(X, Y), ...]>
        self.viruses = set()   # All virus regions
        self.walls = 0
        totalArea = 0
        totalInfectedNeighbors = 0

        totalArea = self.countRegions()
        if totalArea == 0:
            return 0   # No regions, no virus to spread

        # Build wall
        while len(self.viruses) > 0:
            minRegion = min(self.region, key=self.region.get)
            virus = self.viruses.pop(minRegion)
            self.walls += len(virus["neighbors"])
            totalInfectedNeighbors += virus["area"] - len(virus["neighbors"])
            for n in virus["neighbors"]:
                self.grid[n[0]][n[1]] = 1
            for n in virus["neighbors"]:
                del self.infectedNeighbors[n]

            for i in range(self.m):
                for j in range(self.n):
                    if self.grid[i][j] == 1 and (i, j) not in virus["neighbors"]:
                        self.dfs(i, j)

        return self.walls + totalInfectedNeighbors

    def countRegions(self):
        index = 0
        for i in range(self.m):
            for j in range(self.n):
                if self.grid[i][j] == 1 and (i, j) not in self.infectedNeighbors:
                    self.viruses.add(index)
                    self.region[index] = self.dfs(i, j)
                    self.infectedNeighbors[index] = []
                    index += 1
        return index

    def dfs(self, i, j):
        visited = [(i, j)]
        infectedNeighbors = []
        area = 1
        queue = collections.deque([(i, j)])
        while len(queue) > 0:
            ci, cj = queue.popleft()
            for ni, nj in [(ci - 1, cj), (ci + 1, cj), (ci, cj - 1), (ci, cj + 1)]:
                if 0 <= ni < self.m and 0 <= nj < self.n:
                    if self.grid[ni][nj] == 1 and (ni, nj) not in visited:
                        visited.append((ni, nj))
                        queue.append((ni, nj))
                        area += 1
                        if (ni, nj) not in infectedNeighbors:
                            infectedNeighbors.append((ni, nj))
        return {"area": area, "neighbors": infectedNeighbors}

