class Solution(object):
    def longestIncreasingPath(self, matrix):
        """
        :type matrix: List[List[int]]
        :rtype: int
        """
        def get_neighbors(i, j):
            res = []
            if i > 0: res.append((i-1, j))
            if i < len(matrix)-1: res.append((i+1, j))
            if j > 0: res.append((i, j-1))
            if j < len(matrix[0])-1: res.append((i, j+1))
            return res

        def dfs(i, j, max_so_far):
            if not 0 <= i < len(matrix) or not 0 <= j < len(matrix[0]):
                return 0
            if matrix[i][j] >= max_so_far:
                return 0
            return 1 + max([dfs(ri, rj, matrix[i][j]) for ri, rj in get_neighbors(i, j)])

        result = []
        for i in range(len(matrix)):
            for j in range(len(matrix[0])):
                result.append(dfs(i, j, float('-inf')))
        return max(result)

