class TrieNode:
    def __init__(self):
        self.children = collections.defaultdict(TrieNode)
        self.word = None

def build_trie(words):
    root = TrieNode()
    for w in words:
        node = root
        for c in w:
            node = node.children[c]
        node.word = w
    return root

class Solution:
    def wordBreak(self, s, words):
        self.root = build_trie(words)
        self.cache = { len(s) : [''] }
        return self.dfs(0, s, self.root)

    def dfs(self, i, s, node):
        if i not in self.cache:
            self.cache[i] = []
            for j in range(i, len(s) + 1):
                if s[j:] in node.children:
                    sublist = self.dfs(j, s, node.children[s[j:]])
                    for sub in sublist:
                        self.cache[i].append((s[j:]) + ' ' + sub)
        return self.cache[i]

