import heapq

def trapRainWater(heightMap):
    if not heightMap or not heightMap[0]:
        return 0

    m, n = len(heightMap), len(heightMap[0])
    if m < 3 or n < 3:
        return 0

    visited = [[False]*n for _ in range(m)]
    heap = []

    # Add four edges to heap
    for i in range(m):
        for j in [0, n-1]:
            visited[i][j] = True
            heapq.heappush(heap, (heightMap[i][j], i, j))
    for j in range(n):
        for i in [0, m-1]:
            visited[i][j] = True
            heapq.heappush(heap, (heightMap[i][j], i, j))

    res = 0
    dirs = [(-1, 0), (1, 0), (0, -1), (0, 1)]
    while heap:
        height, i, j = heapq.heappop(heap)
        for d in dirs:
            ni, nj = i+d[0], j+d[1]
            if ni < 0 or ni >= m or nj < 0 or nj >= n or visited[ni][nj]:
                continue
            if height > heightMap[ni][nj]:
                res += height-heightMap[ni][nj]
            visited[ni][nj] = True
            heapq.heappush(heap, (max(height, heightMap[ni][nj]), ni, nj))
    return res

