class Solution:
    def maxSumSubmatrix(self, matrix, k):
        if not matrix or not matrix[0]:
            return 0

        m, n = len(matrix), len(matrix[0])
        max_sum = float('-inf')

        for l in range(n):
            sums = [0]*m
            for r in range(l, n):
                for i in range(m):
                    sums[i] += matrix[i][r]
                curr_sum, curr_max = 0, float('-inf')
                prefix_sums = []
                for s in sums:
                    curr_sum += s
                    if curr_sum > k:
                        curr_sum = 0
                        continue

                    if curr_sum == k:
                        return k
                    elif curr_sum < curr_max:
                        curr_max = curr_sum

                    prefix_sums.append(curr_sum)
                max_sum = max(max_sum, curr_max)

                # handle duplicates
                for i in range(len(prefix_sums) - 1, -1, -1):
                    for j in range(i - 1, -1, -1):
                        if prefix_sums[i] - prefix_sums[j] <= k:
                            max_sum = max(max_sum, prefix_sums[i] - prefix_sums[j])
                            break

        return max_sum

