def solve(self, board):
    def capture(i, j):
        if i < 0 or i >= len(board) or j < 0 or j >= len(board[0]) or board[i][j] != 'O':
            return
        board[i][j] = 'E'
        capture(i + 1, j)
        capture(i - 1, j)
        capture(i, j + 1)
        capture(i, j - 1)

    if not board:
        return

    # Capture along border 'O's
    for i in range(len(board)):
        capture(i, 0)
        capture(i, len(board[0]) - 1)
    for j in range(len(board[0])):
        capture(0, j)
        capture(len(board) - 1, j)

