    def fourSum(self, nums: List[int], target: int) -> List[List[int]]:
        nums.sort()
        ans = []
        quad = []
        self.findNSum(nums, target, 4, quad, ans)
        return ans

    def findNSum(self, nums: List[int], target: int, N: int, quad: List[int], ans: List[List[int]]):
        if len(nums) < N or N < 2: 
            return
        if N == 2:
            lo, hi = 0, len(nums) - 1
            while lo < hi:
                if nums[lo] + nums[hi] == target:
                    ans.append(quad + [nums[lo], nums[hi]])
                    while lo < hi and nums[lo] == nums[lo + 1]:
                        lo += 1
                    while lo < hi and nums[hi] == nums[hi - 1]:
                        hi -= 1
                    lo += 1
                    hi -= 1
                elif nums[lo] + nums[hi] < target:
                    lo += 1
                else:
                    hi -= 1
        else:
            for i in range(0, len(nums) - N + 1):
                if target < nums[i] * N or target > nums[-1] * N:
                    break
                if i == 0 or (i > 0 and nums[i - 1] != nums[i]):
                    self.findNSum(nums[i + 1:], target - nums[i], N - 1, quad + [nums[i]], ans)
        return

