class Solution(object):
    def minimumTotal(self, triangle):
        """
        :type triangle: List[List[int]]
        :rtype: int
        """
        for i in range(len(triangle)-2, -1, -1):
            for j in range(len(triangle[i])):
                triangle[i][j] += min(triangle[i+1][j], triangle[i+1][j+1])
        return triangle[0][0]

integer-to-english-words.solution:
class Solution:
    def numberToWords(self, num):
        if num == 0:
            return "Zero"

        to19 = 'One Two Three Four Five Six Seven Eight Nine Ten Eleven Twelve ' \
               'Thirteen Fourteen Fifteen Sixteen Seventeen Eighteen Nineteen'.split()
        tens = 'Twenty Thirty Forty Fifty Sixty Seventy Eighty Ninety'.split()

        def words(num):
            if num < 20:
                return to19[num-1:num]
            if num < 100:
                return [tens[num//10-2]] + words(num%10)
            if num < 1000:
                return [to19[num//100-1]] + ['Hundred'] + words(num%100)
            for p, w in enumerate(('Thousand', 'Million', 'Billion'), 1):
                if num < 1000**(p+1):
                    return words(num//(1000**p)) + [w] + words(num%(1000**p))

        return ' '.join(words(num))

def numberToWords(self, num):
    lookup = {
        1e9: 'Billion', 1e6: 'Million', 1e3: 'Thousand', 1e2: 'Hundred',
        90: 'Ninety', 80: 'Eighty', 70: 'Seventy', 60: 'Sixty',
        50: 'Fifty', 40: 'Forty', 30: 'Thirty', 20: 'Twenty', 19: 'nineteen',
        18: 'Eighteen', 17: 'Seventeen', 16: 'Sixteen', 15: 'Fifteen',
        14: 'Fourteen', 13: 'Thirteen', 12: 'Twelve', 11: 'Eleven',
        10: 'Ten', 9: 'Nine', 8: 'Eight', 7: 'Seven', 6: 'Six', 5: 'Five',
        4: 'Four', 3: 'Three', 2: 'Two', 1: 'One'
    }
    result = []
    for val, word in lookup.items():
        if num >= val:
            count, num = divmod(num, val)
            if count == 1:
                result.append(word)
            else:
                result.extend([word, ''])
            if num == 0:
                break
    return ' '.join(result)

redundant-connection-ii.solution:
class UnionFind:
    def __init__(self, n):
        self.parent = [i for i in range(n)]

    def find(self, x):
        if self.parent[x] != x:
            self.parent[x] = self.find(self.parent[x])
        return self.parent[x]

    def union(self, x, y):
        rootX = self.find(x)
        rootY = self.find(y)
        if rootX != rootY:
            self.parent[rootX] = rootY
            return True
        else:
            return False

def findRedundantDirectedConnection(edges):
    n = len(edges)
    uf = UnionFind(n + 1)
    parent = list(range(n + 1))
    conflict, cycle = None, None
    for i, (u, v) in enumerate(edges):
        if parent[v] != v:
            conflict = (parent[v], v)
            edges[i][1] = conflict[1] = -1
        parent[v] = u
    for u, v in edges:
        if v != -1:
            if uf.union(u, v):
                cycle = (u, v)
            else:
                return [u, v] if conflict and conflict[1] == v else [u, v] if conflict and conflict[1] == -1 else [v, u]
    return cycle if cycle else conflict

