class Solution:
    def cherryPickup(self, grid):
        N = len(grid)
        dp = [[[-1]*(N, 0) for _ in range(N)] for _ in range(N)]
        dp[N-1][N-1][0] = grid[N-1][N-1]

        def update_dp(x1, y1, x2, y2, ch):
            cherries = 0
            if ch == 1 or (x1 == x2 and y1 == y2):
                cherries = grid[x1][y1]
            else:
                cherries = grid[x1][y1] + grid[x2][y2]

            dp[x1][y1][x2 - y2] = cherries

        for t in range(N*N - 1, 0, -1):
            for x1 in range(N):
                y1 = t - x1
                if y1 < 0 or y1 >= N: continue
                for x2 in range(N):
                    y2 = t - x2
                    if y2 < 0 or y2 >= N: continue

                    cherries = dp[x1][y1][x2 - y2]
                    if cherries == -1: continue
                    for dx1, dy1 in ((1,0), (0,1), (-1,0), (0,-1)):
                        nx1, ny1 = x1+dx1, y1+dy1
                        if not (0 <= nx1 < N and 0 <= ny1 < N): continue
                        if grid[nx1][ny1] == -1: continue
                        for dx2, dy2 in ((1,0), (0,1), (-1,0), (0,-1)):
                            nx2, ny2 = x2+dx2, y2+dy2
                            if not (0 <= nx2 < N and 0 <= ny2 < N): continue
                            if grid[nx2][ny2] == -1: continue
                            new_cherries = cherries
                            if nx1 == nx2 and ny1 == ny2:
                                new_cherries += grid[nx1][ny1]
                            dp[nx1][ny1][nx2 - ny2] = max(dp[nx1][ny1][nx2 - ny2], new_cherries)

        return max(0, dp[0][0][0])

