class Solution(object):
    def canJump(self, nums):
        """
        :type nums: List[int]
        :rtype: bool
        """
        last_position = len(nums) - 1

        for i in range(len(nums)-1, -1, -1):
            if i + nums[i] >= last_position:
                last_position = i

        return last_position == 0

minimum-path-sum.solution:
class Solution(object):
    def minPathSum(self, grid):
        """
        :type grid: List[List[int]]
        :rtype: int
        """
        m, n = len(grid), len(grid[0])

        # Iterate through the grid
        for i in range(m):
            for j in range(n):

                # If it's the first row, the path is the sum of the path to the left
                if i == 0 and j > 0:
                    grid[i][j] += grid[i][j - 1]

                # If it's the first column, the path is the sum of the path above
                elif j == 0 and i > 0:
                    grid[i][j] += grid[i - 1][j]

                # For any other cell, the path is the minimum of the path to the left or to the top, plus the value of the cell itself
                elif i > 0 and j > 0:
                    grid[i][j] += min(grid[i - 1][j], grid[i][j - 1])

        # The bottom right cell contains the minimum path sum
        return grid[-1][-1]

