class Solution:
    def splitArray(self, nums, k):
        left, right = max(nums), sum(nums)

        while left < right:
            mid, cnt = left + (right - left) // 2, 1
            s = 0
            for n in nums:
                if s + n > mid:
                    s = n
                    cnt += 1
                else:
                    s += n
            if cnt <= k:
                right = mid
            else:
                left = mid + 1
        return left

