class Solution(object):
    def nearestPalindromic(self, n):
        """
        :type n: str
        :rtype: str
        """
        l = len(n)
        c = int("1"+"0"*(l-1)+"1")
        candidates = [c*10**(l-1) + reverse(c) for c in (c-1, c, c+1)]
        res = max([c for c in candidates if str(c) != n]
                   + [c for c in candidates if c > int(n) and c % 10**(l-1) == 1]
                   + [c for c in candidates if c < int(n) and reverse(c) % 10**(l-1) == 1]
                  )
        return str(res)

def reverse(x):
    res = 0
    while x:
        res = res * 10 + x % 10
        x //= 10
    return res

