class Solution(object):
    def canCross(self, stones):
        """
        :type stones: List[int]
        :rtype: bool
        """
        stones = sorted([0] + stones)
        stone_set = set(stones)
        jump = {x: {} for x in stones}

        def dfs(position, k):
            if position == stones[-1]: 
                return True
            if k <= 0 or position not in stone_set: 
                return False

            for step in [k-1, k, k+1]:
                if step > 0 and jump.get(position+step, {}).get(k-1) is not None:
                    if dfs(position+step, k-1): 
                        return True
            jump[position][k] = True
            return False

        return dfs(stones[1], 1)

