class Solution(object):
    def lengthOfLongestSubstring(self, s):
        """
        :type s: str
        :rtype: int
        """
        # Dictionary to save the last positions of each character.
        last_seen = {}
        start = 0 
        longest = [0, 1] # longest length & substring

        for i, char in enumerate(s):
            # if character is seen and is in the current substring
            if char in last_seen and last_seen[char] >= start:
                # move the start to the next character of the repeated character
                start = last_seen[char] + 1
            else:
                if i - start + 1 > longest[0]:
                    longest = [i - start + 1, s[start:i+1]]

            last_seen[char] = i

        return longest[0]

