class Solution(object):
    def maxChunksToSorted(self, arr):
        stack = []
        for a in arr:
            if stack and a < stack[-1]:
                m = stack.pop()
                while stack and a < stack[-1]:
                    stack.pop()
                stack.append(m)
            else:
                stack.append(a)
        return len(stack)

