class Solution(object):
    def minDistance(self, word1, word2):
        m, n = len(word1), len(word2)
        dp = [[0] * (n + 1) for _ in range(m + 1)]

        for i in range(m + 1):
            dp[i][0] = i

        for j in range(n + 1):
            dp[0][j] = j

        for i in range(1, m + 1):
            for j in range(1, n + 1):
                if word1[i - 1] == word2[j - 1]:
                    dp[i][j] = dp[i - 1][j - 1]
                else:
                    dp[i][j] = min(dp[i - 1][j], dp[i][j - 1], dp[i - 1][j - 1]) + 1

        return dp[m][n]

hamming-distance.solution:
class Solution(object):
    def hammingDistance(self, x, y):
        """
        :type x: int
        :type y: int
        :rtype: int
        """
        bin_x = bin(x)[2:]
        bin_y = bin(y)[2:]

        if len(bin_x) > len(bin_y):
            bin_y = "0" * (len(bin_x) - len(bin_y)) + bin_y
        elif len(bin_x) < len(bin_y):
            bin_x = "0" * (len(bin_y) - len(bin_x)) + bin_x

        return bin_x.count("1") + bin_y.count("1")

reverse-pairs.solution:
class Solution(object):
    def reversePairs(self, nums):
        """
        :type nums: List[int]
        :rtype: int
        """
        def merge_sort(start, end):
            if start >= end:
                return 0

            # Find the index of mid
            mid = (start + end) // 2

            # recursively find the reverse pairs in the left half and right half
            count = merge_sort(start, mid) + merge_sort(mid + 1, end)

            # Merge the two halves with a stable merge
            j = mid + 1
            for i in range(start, mid + 1):
                # while the right half's number is greater or equal, and the left half has a number left, count the pairs and move the right pointer forward
                while j <= end and nums[i] > 2 * nums[j]:
                    count += mid - i + 1
                    j += 1

            nums[start:end + 1] = sorted(nums[start:end + 1])
            return count

        return merge_sort(0, len(nums) - 1)

