from collections import Counter
class Solution(object):
    def isRectangleCover(self, rectangles):
        points = Counter()
        area, min_x, min_y, max_x, max_y = 0, rectangles[0][0], rectangles[0][1], rectangles[0][2], rectangles[0][3]
        for x, y, a, b in rectangles:
            # Update min and max values
            min_x, min_y, max_x, max_y = min(min_x, x), min(min_y, y), max(max_x, a), max(max_y, b)

            # Update area counter using difference of coordinates
            area += (a - x) * (b - y)

            # Update points counter using (x,y), (x,b), (a,y), (a,b)
            for i, j in [(x, y), (x, b), (a, y), (a, b)]:
                points[(i, j)] += 1

        # Check if total formed area and other calculated areas sum up to 0
        if area != (max_x - min_x) * (max_y - min_y):
            return False

        # Check if frequency of each points is either 0, 2 or 4
        for (x, y), v in points.items():
            if v not in [2, 4]:
                return False
        return True

