from collections import deque

def slidingPuzzle(board):
    if board[0][0] != 0 or board[0][1] != 1 or board[0][2] != 2:
        return -1

    start = (tuple(board[0]), tuple(board[1]))
    goal = ((1, 2, 3), (4, 5, 0))

    moves = {start: 0}
    queue = deque([start])

    directions = [(0, 1), (0, -1), (1, 0), (-1, 0)]

    while queue:
        current = queue.popleft()

        if current == goal:
            return moves[current]

        zero_i, zero_j = divmod(reversed(current[0].index(0)), 3)
        for di, dj in directions:
            new_i, new_j = zero_i + di, zero_j + dj

            if 0 <= new_i < 2 and 0 <= new_j < 3:
                zero_neighbor = (list(current[0]), list(current[1]))
                zero_neighbor[zero_i][zero_j], zero_neighbor[new_i][new_j] = zero_neighbor[new_i][new_j], zero_neighbor[zero_i][zero_j]

                new_state = (tuple(zero_neighbor[0]), tuple(zero_neighbor[1]))

                if new_state not in moves:
                    moves[new_state] = moves[current] + 1
                    queue.append(new_state)

    return -1

