        :type t: str
        :rtype: bool
        """
        if len(s) != len(t):
            return False

        s_to_t = {}
        t_to_s = {}

        for char_s, char_t in zip(s, t):
            if char_s not in s_to_t and char_t not in t_to_s:
                s_to_t[char_s] = char_t
                t_to_s[char_t] = char_s
            elif char_s in s_to_t and char_t in t_to_s:
                if s_to_t[char_s] != char_t or t_to_s[char_t] != char_s:
                    return False
            else:
                return False
        return True

