            l, r = i + 1, len(nums) - 1

            while l < r:
                sum_ = nums[i] + nums[l] + nums[r]

                if abs(diff) > abs(target - sum_):
                    diff, res = target - sum_, sum_

                if sum_ > target:
                    r -= 1
                elif sum_ < target:
                    l += 1
                else:
                    return sum_

        return res

