class Solution:
    def strongPasswordChecker(self, password):
        # check length
        if len(password) < 6:
            return 6 - len(password)
        elif len(password) > 20:
            return len(password) - 20

        # check conditions
        has_lower = has_upper = has_digit = has_special = False
        for i, c in enumerate(password):
            if not has_lower and c.islower():
                has_lower = True
            elif not has_upper and c.isupper():
                has_upper = True
            elif not has_digit and c.isdigit():
                has_digit = True
            elif not has_special and c in '!@#$%^&*()':
                has_special = True

            if i > 0 and i < len(password) - 1 and password[i] == password[i-1] == password[i+1]:
                return max(3 - len(password), 0)

        # no repeating characters or conditions not met
        return max(has_lower + has_upper + has_digit + has_special - 4, 0)

