class Solution(object):
    def convert(self, s, numRows):
        """
        :type s: str
        :type numRows: int
        :rtype: str
        """
        if numRows < 2:
            return s
        res = ["" for _ in range(numRows)]
        going_down = True
        cur_row = 0
        for char in s:
            res[cur_row] += char
            if cur_row == numRows - 1 and going_down:
                going_down = False
            elif cur_row == 0 and not going_down:
                going_down = True
            if going_down:
                cur_row += 1
            else:
                cur_row -= 1
        return "".join(res)

