            i = intervals.pop()

            # if i[1] is the largest one, we can pick 2 numbers
            if i[1] == answer + 2:
                t.add(i[0])
                t.add(i[0] + 1)
            # if i[1] is the second largest one, we can pick 1 number
            elif i[1] == answer + 1:
                t.add(i[0] + 1)

