import collections

class Solution(object):
    def countOfAtoms(self, formula):
        """
        :type formula: str
        :rtype: str
        """
        def parse(i, formula):
            count = collections.Counter()
            while i < len(formula):
                if formula[i] == '(':
                    i, ctr = parse(i+1, formula)
                    count += collections.Counter({k:v*ctr for k, v in count.items()})
                elif formula[i] == ')':
                    j = i+1
                    while j < len(formula) and formula[j].isdigit():
                        j += 1
                    mult = int(formula[i+1:j]) if j > i+1 else 1
                    count = {k: v*mult for k, v in count.items()}
                    return j, count
                else:
                    j = i+1
                    while j < len(formula) and formula[j].islower():
                        j += 1
                    name = formula[i:j]
                    i = j

                    while j < len(formula) and formula[j].isdigit():
                        j += 1
                    mult = int(formula[i:j]) if j > i else 1
                    count[name] += mult
            return i, count

        _, ctr = parse(0, formula)
        return "".join(name+(str(ctr[name]) if ctr[name] > 1 else "") 
                for name in sorted(ctr))

