class Solution(object):
    def generateParenthesis(self, n):
        """
        :type n: int
        :rtype: List[str]
        """
        # Initial list with the first pair of parentheses
        lst = ['()']

        # Recursive function to generate all pairs
        def generate(prev, open, close, lst):
            if open > 0:
                generate(prev + '(', open - 1, close, lst)
            if close > open:
                generate(prev + ')', open, close - 1, lst)

            # Add new pair of parentheses to the list
            if prev and open == 0 and close == 0:
                lst.append(prev)

        generate('', n-1, n, lst)

        return lst

