class Solution:
    def fractionToDecimal(self, numerator, denominator):
        result = ''
        num = numerator
        den = denominator
        # check if the result is negative or positive
        if num * den < 0:
            result += '-'

        # turn the num and den to positive
        num = abs(num)
        den = abs(den)

        # add the int part
        result += str(num//den)
        remainder = num % den
        # if no remainder, return the result
        if remainder == 0:
            return result
        else:
            result += '.'

        remainder_dict = {}

        while remainder != 0:
            if remainder in remainder_dict:
                result = result[:remainder_dict[remainder]] + '(' + result[remainder_dict[remainder]:] + ')'
                break
            else:
                remainder_dict[remainder] = len(result)
                remainder *= 10
                result += str(remainder//den)
                remainder = remainder % den

        return result

