    def maximalRectangle(self, matrix):
        if not matrix:
            return 0
        m, n = len(matrix), len(matrix[0])

        height = [0] * (n + 1) #Add a sentinel to avoid index error
        max_area = 0

        for i in range(m):
            for j in range(n):
                height[j] = height[j] + 1 if matrix[i][j] == '1' else 0 #Transform matrix to height list

            stack = [-1] #Stack with index -1 is used to calculate max_area in the last loop
            for k in range(n + 1):
                while height[k] < height[stack[-1]]:
                    h = height[stack.pop()]
