def backtrack(self, result, intermediate, nums, size, start):
    if len(intermediate) == size:
        result.append(intermediate[:])
        return
    for i in range(start, len(nums)):
        intermediate.append(nums[i])
        self.backtrack(result, intermediate, nums, size, i + 1)
        intermediate.pop()

