class Solution(object):
    def isPerfectSquare(self, num):
        if num < 2:
            return True

        left, right = 2, num // 2

        while left <= right:
            x = left + (right - left) // 2
            guess_squared = x * x
            if guess_squared == num:
                return True
            if guess_squared < num:
                left = x + 1
            else:
                right = x - 1

