class Solution(object):
    def countBits(self, n):
        """
        :type n: int
        :rtype: List[int]
        """
        result = [0] * (n + 1)
        for i in range(1, n + 1):
            if i % 2 == 0:
                result[i] = result[i // 2]
            else:
                result[i] = result[i // 2] + 1
        return result

scramble-string.solution:
from functools import lru_cache

class Solution(object):
    def isScramble(self, s1, s2):
        """
        :type s1: str
        :type s2: str
        :rtype: bool
        """

        @lru_cache(maxsize=None)
        def solve(i, j, k, m):
            if s1[i:m] == s2[j:k]:
                return True
            if sorted(s1[i:m]) != sorted(s2[j:k]):
                return False
            for m in range(i+1, m):
                if solve(i, j, k, m) and solve(m, j, k, m):
                    return True
                if solve(i, m, j, k) and solve(m, k, i, m):
                    return True
            return False

        if len(s1) != len(s2):
            return False
        return solve(0, 0, len(s1), len(s1))

simplify-path.solution:
class Solution(object):
    def simplifyPath(self, path):
        stack = []
        for segment in path.split('/'):
            if segment == '..':
                if stack:
                    stack.pop()
            elif segment and segment != '.':
                stack.append(segment)
        return '/' + '/'.join(stack)

word-search-ii.solution:
class Solution(object):
    def findWords(self, board, words):
        trie = {}
        for word in words:
            node = trie
            for letter in word:
                node = node.setdefault(letter, {})
            node['#'] = word 
        self.board = board
        self.trie = trie
        self.m, self.n = len(board), len(board[0])
        self.res = set()

        for i in range(self.m):
            for j in range(self.n):
                if board[i][j] in self.trie:
                    self._dfs(i, j, trie)
        return list(self.res)

    def _dfs(self, i, j, trie):
        letter = self.board[i][j]
        currentNode = trie[letter]
        matchWord = currentNode.pop('#', False)
        if matchWord:
            self.res.add(matchWord)

        self.board[i][j] = '$'
        for (di, dj) in [(1, 0), (-1, 0), (0, 1), (0, -1)]:
            newi, newj = i+di, j+dj
            if newi < 0 or newi >= self.m or newj < 0 or newj >= self.n:
                continue
            if self.board[newi][newj] in currentNode:
                self._dfs(newi, newj, currentNode)
        self.board[i][j] = letter

        # Optimization: incrementally remove the matched characters to prevent duplicates 
        if not currentNode:
            trie.pop(letter)

