class Solution(object):
    def numberOfArithmeticSlices(self, nums):
        """
        :type nums: List[int]
        :rtype: int
        """
        total = 0
        dp = [{} for _ in range(len(nums))]

        for i in range(len(nums)):
            for j in range(i):
                diff = nums[i] - nums[j]

                if diff in dp[j]:
                    dp[i][diff] = dp[i].get(diff, 0) + dp[j][diff] + 1
                    total += dp[j][diff]
                else:
                    dp[i][diff] = dp[i].get(diff, 0) + 1

        return total

