class Solution:
    def findAllConcatenatedWordsInADict(self, words):
        """
        :type words: List[str]
        :rtype: List[str]
        """

        def can_split(word, word_set):
            if not word_set:
                return False
            dp = [False] * (len(word) + 1)
            dp[0] = True
            for i in range(1, len(word) + 1):
                for j in range(i):
                    if dp[j] and word[j:i] in word_set:
                        dp[i] = True
                        break
            return dp[len(word)]

        word_set = set(words)
        words.sort(key=len)
        result = []
        for word in words:
            if can_split(word, word_set):
                result.append(word)
        return result

