            return self.convertToBase7(num // 7) + str(num % 7)

n-queens-ii.solution:
class Solution:
    def totalNQueens(self, n: int) -> int:
        def is_safe(board, row, col):
            # Check this row on left side
            for i in range(col):
                if board[row][i] == 1:
                    return False

            # Check upper diagonal on left side
            for i, j in zip(range(row, -1, -1), range(col, -1, -1)):
                if board[i][j] == 1:
                    return False

            # Check lower diagonal on left side
            for i, j in zip(range(row, n, 1), range(col, -1, -1)):
                if board[i][j] == 1:
                    return False

            return True

        def solve_nqutil(board, col):
            # base case
            if col >= n:
                return 1

            count = 0
            for i in range(n):
                if is_safe(board, i, col):
                    board[i][col] = 1
                    count += solve_nqutil(board, col + 1)
                    board[i][col] = 0  # backtrack
            return count

        board = [[0, ] * n for _ in range(n)]
        return solve_nqutil(board, 0)

word-search.solution:
class Solution:
    def exist(self, board: List[List[str]], word: str) -> bool:
        def search(r, c, i):
            if i == len(word): return True
            if r < 0 or c < 0 or r >= len(board) or c >= len(board[0]) or word[i] != board[r][c]: return False
            board[r][c] = None
            found = search(r+1, c, i+1) or search(r-1, c, i+1) or search(r, c+1, i+1) or search(r, c-1, i+1)
            board[r][c] = word[i]
            return found

        for r in range(len(board)):
            for c in range(len(board[0])):
                if search(r, c, 0): return True
        return False

